import heapq

class KthLargest:
    def __init__(self, k: int, nums: list[int]):
        self.k = k
        self.heap = nums
        heapq.heapify(self.heap)        # turn list into a heap in O(n)
        while len(self.heap) > k:       # trim to size k
            heapq.heappop(self.heap)

    def add(self, val: int) -> int:
        heapq.heappush(self.heap, val)
        if len(self.heap) > self.k:
            heapq.heappop(self.heap)    # keep only k largest
        return self.heap[0]             # top of min-heap is kth largest

class Solution:
    def lastStoneWeight(self, stones: list[int]) -> int:
        while len(stones) > 1:
            stones.sort()  # sort each iteration
            first = stones.pop()   # heaviest
            second = stones.pop()  # second heaviest
            if first != second:
                stones.append(first - second)
        return stones[0] if stones else 0

