import heapq

class Solution:
    def kClosest(self, points: list[list[int]], k: int) -> list[list[int]]:
        heap = []  # max-heap of (-distance, point)
        for x, y in points:
            dist = x*x + y*y
            heapq.heappush(heap, (-dist, [x, y]))  # negate dist for max-heap
            if len(heap) > k:
                heapq.heappop(heap)  # remove the farthest
        return [point for (_, point) in heap]

