class Solution:
    def kClosest(self, points: list[list[int]], k: int) -> list[list[int]]:
        def dist(p):
            return p[0]**2 + p[1]**2

        def partition(left, right, pivot_idx):
            pivot_dist = dist(points[pivot_idx])
            # move pivot to end
            points[pivot_idx], points[right] = points[right], points[pivot_idx]
            store_idx = left
            for i in range(left, right):
                if dist(points[i]) < pivot_dist:
                    points[i], points[store_idx] = points[store_idx], points[i]
                    store_idx += 1
            # move pivot to its final place
            points[store_idx], points[right] = points[right], points[store_idx]
            return store_idx

        def select(left, right, k):
            if left == right:
                return
            pivot_idx = random.randint(left, right)
            pivot_idx = partition(left, right, pivot_idx)
            if k == pivot_idx:
                return
            elif k < pivot_idx:
                select(left, pivot_idx - 1, k)
            else:
                select(pivot_idx + 1, right, k)

        select(0, len(points) - 1, k - 1)
        return points[:k]

