import random

class Solution:
    def findKthLargest(self, nums: list[int], k: int) -> int:
        k = len(nums) - k  # convert to k-th smallest (0-indexed)

        def partition(left, right, pivot_idx):
            pivot = nums[pivot_idx]
            # move pivot to end
            nums[pivot_idx], nums[right] = nums[right], nums[pivot_idx]
            store_idx = left
            for i in range(left, right):
                if nums[i] < pivot:
                    nums[i], nums[store_idx] = nums[store_idx], nums[i]
                    store_idx += 1
            # move pivot to its final place
            nums[store_idx], nums[right] = nums[right], nums[store_idx]
            return store_idx

        def select(left, right):
            if left == right:
                return nums[left]
            pivot_idx = random.randint(left, right)
            pivot_idx = partition(left, right, pivot_idx)
            if k == pivot_idx:
                return nums[k]
            elif k < pivot_idx:
                return select(left, pivot_idx - 1)
            else:
                return select(pivot_idx + 1, right)

        return select(0, len(nums) - 1)

import heapq

class MedianFinder:
    def __init__(self):
        self.small = []  # max-heap (negate values)
        self.large = []  # min-heap

    def addNum(self, num: int) -> None:
        # always add to small first (as a max-heap)
        heapq.heappush(self.small, -num)

        # ensure every element in small <= every element in large
        if self.small and self.large and (-self.small[0] > self.large[0]):
            val = -heapq.heappop(self.small)
            heapq.heappush(self.large, val)

        # balance sizes (small can have at most 1 more element than large)
        if len(self.small) > len(self.large) + 1:
            val = -heapq.heappop(self.small)
            heapq.heappush(self.large, val)
        if len(self.large) > len(self.small):
            val = heapq.heappop(self.large)
            heapq.heappush(self.small, -val)

    def findMedian(self) -> float:
        if len(self.small) > len(self.large):
            return -self.small[0]
        return (-self.small[0] + self.large[0]) / 2
